<?php session_start(); require 'db.php'; if(!isset($_SESSION['user_id'])) exit; $me=$_SESSION['user_id']; $other=$_GET['other_id']; $sql="SELECT * FROM messages WHERE (sender_id=? AND receiver_id=?) OR (sender_id=? AND receiver_id=?) ORDER BY id ASC"; $stmt=$pdo->prepare($sql); $stmt->execute([$me,$other,$other,$me]); $msgs=$stmt->fetchAll(PDO::FETCH_ASSOC); if(empty($msgs)) echo '<div style="text-align:center;margin-top:50px;color:#999;">Diga olá! 👋</div>'; foreach($msgs as $m){ $c=($m['sender_id']==$me)?'msg-sent':'msg-received'; echo '<div class="message-bubble '.$c.'">'.nl2br(htmlspecialchars($m['message'])).'<span class="msg-time">'.date('H:i',strtotime($m['created_at'])).'</span></div>'; } ?>
